import React, { useState } from 'react';
import { useResponsive } from '../../hooks/useResponsive';
import type { AssetFiltersProps, AssetFiltersState } from '../../types/components';

const DEFAULT_FILTERS: AssetFiltersState = {
  verified_only: false,
  min_accounts: null,
  max_accounts: null,
  has_domain: false,
  sort_by: 'num_accounts',
  order: 'desc',
  asset_type: '',
  code_pattern: '',
  min_volume_24h: null,
  volatility: '',
  reputation_min: 0,
  verification_level: '',
};

const PRESET_STORAGE_KEY = 'asset_filter_presets';

interface FilterPreset {
  name: string;
  filters: AssetFiltersState;
}

function loadPresets(): FilterPreset[] {
  try {
    return JSON.parse(localStorage.getItem(PRESET_STORAGE_KEY) || '[]') as FilterPreset[];
  } catch {
    return [];
  }
}

function savePresets(presets: FilterPreset[]) {
  localStorage.setItem(PRESET_STORAGE_KEY, JSON.stringify(presets));
}

export default function AssetFilters({ filters, onChange }: AssetFiltersProps) {
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [presets, setPresets] = useState(loadPresets);
  const [presetName, setPresetName] = useState('');
  const [showPresetInput, setShowPresetInput] = useState(false);
  const { isMobile } = useResponsive();

  const handleFilterChange = (key: keyof AssetFiltersState, value: AssetFiltersState[keyof AssetFiltersState]) => {
    onChange({ [key]: value });
  };

  const resetFilters = () => {
    onChange({ ...DEFAULT_FILTERS });
  };

  const savePreset = () => {
    if (!presetName.trim()) return;
    const newPreset = { name: presetName.trim(), filters: { ...filters } };
    const updated = [...presets, newPreset];
    setPresets(updated);
    savePresets(updated);
    setPresetName('');
    setShowPresetInput(false);
  };

  const loadPreset = (preset: FilterPreset) => {
    onChange({ ...DEFAULT_FILTERS, ...preset.filters });
  };

  const deletePreset = (index: number) => {
    const updated = presets.filter((_, i) => i !== index);
    setPresets(updated);
    savePresets(updated);
  };

  // Compute active filter count for badge
  const activeCount = [
    filters.verified_only,
    filters.has_domain,
    filters.min_accounts,
    filters.max_accounts,
    filters.asset_type,
    filters.code_pattern,
    filters.min_volume_24h,
    filters.volatility,
    filters.reputation_min > 0,
    filters.verification_level,
  ].filter(Boolean).length;

  const containerStyle: React.CSSProperties = {
    background: 'var(--bg-card)',
    border: '1px solid var(--border)',
    borderRadius: 'var(--radius-lg)',
    padding: isMobile ? '16px' : '20px',
  };

  const headerStyle: React.CSSProperties = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '16px',
  };

  const titleStyle: React.CSSProperties = {
    fontSize: '14px',
    fontWeight: 600,
    color: 'var(--text-primary)',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
  };

  const badgeStyle: React.CSSProperties = {
    background: 'var(--cyan)',
    color: 'var(--bg-base)',
    borderRadius: '999px',
    fontSize: '10px',
    fontWeight: 700,
    padding: '1px 6px',
  };

  const btnRowStyle: React.CSSProperties = { display: 'flex', gap: '8px', flexWrap: 'wrap' };

  const btnStyle: React.CSSProperties = {
    background: 'none',
    border: '1px solid var(--border)',
    borderRadius: 'var(--radius-sm)',
    color: 'var(--text-secondary)',
    fontSize: '12px',
    padding: '6px 12px',
    cursor: 'pointer',
    fontFamily: 'var(--font-mono)',
    transition: 'var(--transition)',
  };

  const gridStyle: React.CSSProperties = {
    display: 'grid',
    gridTemplateColumns: isMobile ? '1fr' : 'repeat(auto-fit, minmax(190px, 1fr))',
    gap: '16px',
    marginBottom: '16px',
  };

  const groupStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '8px' };

  const labelStyle: React.CSSProperties = {
    fontSize: '11px',
    fontWeight: 600,
    color: 'var(--text-secondary)',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
  };

  const selectStyle: React.CSSProperties = {
    background: 'var(--bg-elevated)',
    border: '1px solid var(--border)',
    borderRadius: 'var(--radius-md)',
    color: 'var(--text-primary)',
    fontSize: '13px',
    fontFamily: 'var(--font-mono)',
    padding: '8px 12px',
    cursor: 'pointer',
  };

  const inputStyle: React.CSSProperties = {
    background: 'var(--bg-elevated)',
    border: '1px solid var(--border)',
    borderRadius: 'var(--radius-md)',
    color: 'var(--text-primary)',
    fontSize: '13px',
    fontFamily: 'var(--font-mono)',
    padding: '8px 12px',
  };

  const checkRowStyle: React.CSSProperties = {
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    cursor: 'pointer',
    padding: '6px 0',
  };

  const chipStyle = (color: string): React.CSSProperties => ({
    background: `${color}20`,
    color,
    border: `1px solid ${color}40`,
    borderRadius: 'var(--radius-sm)',
    fontSize: '11px',
    fontWeight: 600,
    padding: '2px 8px',
    display: 'inline-flex',
    alignItems: 'center',
    gap: '4px',
  });

  const dividerStyle: React.CSSProperties = {
    borderTop: '1px solid var(--border)',
    paddingTop: '16px',
    marginTop: '4px',
  };

  type ActiveChip = {
    label: string;
    color: string;
    key: keyof AssetFiltersState;
    reset: AssetFiltersState[keyof AssetFiltersState];
  };

  const activeChips = ([
    filters.verified_only && { label: 'Verified Only', color: 'var(--green)', key: 'verified_only' as const, reset: false as const },
    filters.has_domain && { label: 'Has Domain', color: 'var(--cyan)', key: 'has_domain' as const, reset: false as const },
    filters.verification_level && { label: `Level: ${filters.verification_level}`, color: 'var(--cyan)', key: 'verification_level' as const, reset: '' as const },
    filters.min_accounts && { label: `Min ${filters.min_accounts} accts`, color: 'var(--text-secondary)', key: 'min_accounts' as const, reset: null },
    filters.max_accounts && { label: `Max ${filters.max_accounts} accts`, color: 'var(--text-secondary)', key: 'max_accounts' as const, reset: null },
    filters.asset_type && { label: filters.asset_type === 'credit_alphanum4' ? '4-char codes' : '12-char codes', color: 'var(--amber)', key: 'asset_type' as const, reset: '' as const },
    filters.code_pattern && { label: `Pattern: ${filters.code_pattern}`, color: 'var(--amber)', key: 'code_pattern' as const, reset: '' as const },
    filters.min_volume_24h && { label: `Vol ≥ $${Number(filters.min_volume_24h).toLocaleString()}`, color: 'var(--green)', key: 'min_volume_24h' as const, reset: null },
    filters.volatility && { label: `Volatility: ${filters.volatility}`, color: 'var(--red)', key: 'volatility' as const, reset: '' as const },
    filters.reputation_min > 0 && { label: `Rep ≥ ${filters.reputation_min}`, color: 'var(--cyan)', key: 'reputation_min' as const, reset: 0 as const },
  ].filter(Boolean)) as ActiveChip[];

  return (
    <div style={containerStyle}>
      {/* Header */}
      <div style={headerStyle}>
        <div style={titleStyle}>
          🔧 Filters
          {activeCount > 0 && <span style={badgeStyle}>{activeCount}</span>}
        </div>
        <div style={btnRowStyle}>
          {presets.length > 0 && (
            <select
              style={{ ...btnStyle, cursor: 'pointer' }}
              defaultValue=""
              onChange={(e) => {
                const idx = parseInt(e.target.value);
                if (!isNaN(idx)) loadPreset(presets[idx]);
                e.target.value = '';
              }}
            >
              <option value="" disabled>📂 Load Preset</option>
              {presets.map((p, i) => (
                <option key={i} value={i}>{p.name}</option>
              ))}
            </select>
          )}
          <button style={btnStyle} onClick={() => setShowPresetInput(!showPresetInput)}>
            💾 Save
          </button>
          <button
            style={btnStyle}
            onClick={() => setShowAdvanced(!showAdvanced)}
          >
            {showAdvanced ? '🔼 Less' : '🔽 More'}
          </button>
          <button style={btnStyle} onClick={resetFilters}>
            ↺ Reset
          </button>
        </div>
      </div>

      {/* Save preset input */}
      {showPresetInput && (
        <div style={{ display: 'flex', gap: '8px', marginBottom: '16px' }}>
          <input
            style={{ ...inputStyle, flex: 1 }}
            placeholder="Preset name..."
            value={presetName}
            onChange={(e) => setPresetName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && savePreset()}
          />
          <button
            style={{ ...btnStyle, background: 'var(--cyan-glow)', color: 'var(--cyan)', borderColor: 'var(--cyan)' }}
            onClick={savePreset}
          >
            Save
          </button>
        </div>
      )}

      {/* Saved presets list */}
      {presets.length > 0 && showPresetInput && (
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', marginBottom: '16px' }}>
          {presets.map((p, i) => (
            <span key={i} style={chipStyle('var(--text-secondary)')}>
              {p.name}
              <span
                style={{ cursor: 'pointer', marginLeft: '4px', color: 'var(--red)' }}
                onClick={() => deletePreset(i)}
              >×</span>
            </span>
          ))}
        </div>
      )}

      {/* Basic filters */}
      <div style={gridStyle}>
        {/* Sort By */}
        <div style={groupStyle}>
          <label style={labelStyle}>Sort By</label>
          <select
            value={filters.sort_by}
            onChange={(e) => handleFilterChange('sort_by', e.target.value)}
            style={selectStyle}
          >
            <option value="num_accounts">Accounts</option>
            <option value="amount">Supply</option>
            <option value="code">Asset Code</option>
            <option value="volume_24h">24h Volume</option>
          </select>
        </div>

        {/* Order */}
        <div style={groupStyle}>
          <label style={labelStyle}>Order</label>
          <select
            value={filters.order}
            onChange={(e) => handleFilterChange('order', e.target.value)}
            style={selectStyle}
          >
            <option value="desc">Descending</option>
            <option value="asc">Ascending</option>
          </select>
        </div>

        {/* Asset Code Type */}
        <div style={groupStyle}>
          <label style={labelStyle}>Code Type</label>
          <select
            value={filters.asset_type || ''}
            onChange={(e) => handleFilterChange('asset_type', (e.target.value || '') as AssetFiltersState['asset_type'])}
            style={selectStyle}
          >
            <option value="">All Types</option>
            <option value="credit_alphanum4">4-char (e.g. USDC)</option>
            <option value="credit_alphanum12">12-char (e.g. LONGASSET)</option>
          </select>
        </div>

        {/* Quick Filters */}
        <div style={groupStyle}>
          <label style={labelStyle}>Quick Filters</label>
          <label style={checkRowStyle}>
            <input
              type="checkbox"
              checked={filters.verified_only}
              onChange={(e) => handleFilterChange('verified_only', e.target.checked)}
              style={{ accentColor: 'var(--cyan)', width: '15px', height: '15px' }}
            />
            <span style={{ fontSize: '13px', color: 'var(--text-primary)' }}>Verified only</span>
          </label>
          <label style={checkRowStyle}>
            <input
              type="checkbox"
              checked={filters.has_domain}
              onChange={(e) => handleFilterChange('has_domain', e.target.checked)}
              style={{ accentColor: 'var(--cyan)', width: '15px', height: '15px' }}
            />
            <span style={{ fontSize: '13px', color: 'var(--text-primary)' }}>Has domain</span>
          </label>
        </div>
      </div>

      {/* Advanced Filters */}
      {showAdvanced && (
        <div style={{ ...gridStyle, ...dividerStyle }}>
          {/* Verification Level */}
          <div style={groupStyle}>
            <label style={labelStyle}>Verification Level</label>
            <select
              value={filters.verification_level || ''}
              onChange={(e) => handleFilterChange('verification_level', e.target.value || '')}
              style={selectStyle}
            >
              <option value="">Any</option>
              <option value="full">✅ Full</option>
              <option value="domain">🌐 Domain</option>
              <option value="manual">🔍 Manual</option>
              <option value="none">⚠️ None</option>
            </select>
          </div>

          {/* Min 24h Volume */}
          <div style={groupStyle}>
            <label style={labelStyle}>Min 24h Volume (USD)</label>
            <input
              type="number"
              value={filters.min_volume_24h || ''}
              onChange={(e) => handleFilterChange('min_volume_24h', e.target.value ? parseFloat(e.target.value) : null)}
              placeholder="e.g. 10000"
              style={inputStyle}
              min="0"
            />
          </div>

          {/* Volatility */}
          <div style={groupStyle}>
            <label style={labelStyle}>Price Volatility</label>
            <select
              value={filters.volatility || ''}
              onChange={(e) => handleFilterChange('volatility', e.target.value || '')}
              style={selectStyle}
            >
              <option value="">Any</option>
              <option value="stable">🟢 Stable (&lt;1% 24h)</option>
              <option value="low">🟡 Low (1–5%)</option>
              <option value="medium">🟠 Medium (5–15%)</option>
              <option value="high">🔴 High (&gt;15%)</option>
            </select>
          </div>

          {/* Min Reputation Score */}
          <div style={groupStyle}>
            <label style={labelStyle}>Min Reputation Score (0–100)</label>
            <input
              type="range"
              min="0"
              max="100"
              step="5"
              value={filters.reputation_min || 0}
              onChange={(e) => handleFilterChange('reputation_min', parseInt(e.target.value))}
              style={{ accentColor: 'var(--cyan)', width: '100%' }}
            />
            <div style={{ fontSize: '12px', color: 'var(--cyan)', textAlign: 'center', fontFamily: 'var(--font-mono)' }}>
              {filters.reputation_min || 0}+
            </div>
          </div>

          {/* Asset Code Pattern */}
          <div style={groupStyle}>
            <label style={labelStyle}>Code Pattern (regex)</label>
            <input
              type="text"
              value={filters.code_pattern || ''}
              onChange={(e) => handleFilterChange('code_pattern', e.target.value)}
              placeholder="e.g. ^USD or BTC$"
              style={inputStyle}
            />
          </div>

          {/* Min Accounts */}
          <div style={groupStyle}>
            <label style={labelStyle}>Min Accounts</label>
            <input
              type="number"
              value={filters.min_accounts || ''}
              onChange={(e) => handleFilterChange('min_accounts', e.target.value ? parseInt(e.target.value) : null)}
              placeholder="e.g. 100"
              style={inputStyle}
              min="0"
            />
          </div>

          {/* Max Accounts */}
          <div style={groupStyle}>
            <label style={labelStyle}>Max Accounts</label>
            <input
              type="number"
              value={filters.max_accounts || ''}
              onChange={(e) => handleFilterChange('max_accounts', e.target.value ? parseInt(e.target.value) : null)}
              placeholder="e.g. 10000"
              style={inputStyle}
              min="0"
            />
          </div>
        </div>
      )}

      {/* Active filter chips */}
      {activeChips.length > 0 && (
        <div style={{
          marginTop: '16px',
          padding: '12px',
          background: 'var(--bg-elevated)',
          borderRadius: 'var(--radius-md)',
          border: '1px solid var(--border)',
        }}>
          <div style={{ fontSize: '11px', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
            Active Filters
          </div>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
            {activeChips.map((chip) => (
              <span
                key={chip.key}
                style={{ ...chipStyle(chip.color), cursor: 'pointer' }}
                onClick={() => handleFilterChange(chip.key, chip.reset)}
                title="Click to remove"
              >
                {chip.label} <span style={{ opacity: 0.7 }}>×</span>
              </span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
